-- WORKING AUTO-FILL SOLUTION for branch_id\n-- This is the confirmed working query provided by the user\n\n-- Step 1: Check current state before update\nSELECT 'BEFORE UPDATE - Subjects without branch_id:' as status;\nSELECT COUNT(*) as subjects_without_branch_id FROM subjects WHERE branch_id IS NULL OR branch_id = '';\n\n-- Step 2: Preview what will be updated\nSELECT 'PREVIEW - What will be updated:' as info;\nSELECT \n    s.subject_code,\n    s.subject,\n    s.class_code,\n    s.school_id,\n    s.branch_id as current_branch_id,\n    c.branch_id as new_branch_id,\n    CASE \n        WHEN c.branch_id IS NOT NULL THEN 'Will be updated'\n        ELSE 'No matching class found'\n    END as update_status\nFROM subjects s\nLEFT JOIN classes c \n  ON s.class_code = c.class_code \n AND s.school_id = c.school_id\nWHERE (s.branch_id IS NULL OR s.branch_id = '')\nLIMIT 10;\n\n-- Step 3: Count how many will be updated vs not found\nSELECT 'UPDATE ANALYSIS:' as analysis;\nSELECT \n    SUM(CASE WHEN c.branch_id IS NOT NULL THEN 1 ELSE 0 END) as will_be_updated,\n    SUM(CASE WHEN c.branch_id IS NULL THEN 1 ELSE 0 END) as no_matching_class,\n    COUNT(*) as total_subjects_needing_branch_id\nFROM subjects s\nLEFT JOIN classes c \n  ON s.class_code = c.class_code \n AND s.school_id = c.school_id\nWHERE (s.branch_id IS NULL OR s.branch_id = '');\n\n-- Step 4: THE WORKING UPDATE QUERY\n-- This is the confirmed working solution\nUPDATE subjects s\nLEFT JOIN classes c \n  ON s.class_code = c.class_code \n AND s.school_id = c.school_id\nSET s.branch_id = c.branch_id\nWHERE (s.branch_id IS NULL OR s.branch_id = '');\n\n-- Step 5: Check results after update\nSELECT 'AFTER UPDATE - Subjects still without branch_id:' as status;\nSELECT COUNT(*) as subjects_still_without_branch_id FROM subjects WHERE branch_id IS NULL OR branch_id = '';\n\n-- Step 6: Show success message\nSELECT \n    CASE \n        WHEN COUNT(*) = 0 THEN '🎉 PERFECT SUCCESS: All subjects now have branch_id!'\n        ELSE CONCAT('✅ PARTIAL SUCCESS: ', \n                   (SELECT COUNT(*) FROM subjects WHERE branch_id IS NOT NULL AND branch_id != ''), \n                   ' subjects updated, ', \n                   COUNT(*), \n                   ' still need manual assignment')\n    END as final_result\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = '';\n\n-- Step 7: Show final distribution\nSELECT 'FINAL DISTRIBUTION by school and branch:' as distribution;\nSELECT \n    s.school_id,\n    s.branch_id,\n    COUNT(*) as subject_count,\n    GROUP_CONCAT(DISTINCT s.section) as sections\nFROM subjects s\nWHERE s.branch_id IS NOT NULL AND s.branch_id != ''\nGROUP BY s.school_id, s.branch_id\nORDER BY s.school_id, s.branch_id;\n\n-- Step 8: Show any subjects that still need manual assignment\nSELECT 'SUBJECTS STILL NEEDING MANUAL ASSIGNMENT:' as remaining;\nSELECT \n    s.subject_code,\n    s.subject,\n    s.school_id,\n    s.class_code,\n    s.section,\n    'No matching class found - needs manual assignment' as reason\nFROM subjects s\nWHERE s.branch_id IS NULL OR s.branch_id = ''\nLIMIT 10;\n\n-- Step 9: Summary statistics\nSELECT 'FINAL SUMMARY:' as summary;\nSELECT \n    COUNT(*) as total_subjects,\n    SUM(CASE WHEN branch_id IS NOT NULL AND branch_id != '' THEN 1 ELSE 0 END) as subjects_with_branch_id,\n    SUM(CASE WHEN branch_id IS NULL OR branch_id = '' THEN 1 ELSE 0 END) as subjects_without_branch_id,\n    ROUND(\n        (SUM(CASE WHEN branch_id IS NOT NULL AND branch_id != '' THEN 1 ELSE 0 END) * 100.0 / COUNT(*)), \n        2\n    ) as completion_percentage\nFROM subjects;\n\n-- Step 10: Verification for enhanced controller\nSELECT 'ENHANCED CONTROLLER READINESS CHECK:' as readiness;\nSELECT \n    CASE \n        WHEN COUNT(*) = 0 THEN '✅ READY: Enhanced subjects controller should work perfectly!'\n        ELSE CONCAT('⚠️ ATTENTION: ', COUNT(*), ' subjects still need branch_id before using enhanced controller')\n    END as controller_readiness\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = '';\n"